CREATE OR REPLACE VIEW vmb_transaction_loan (seq_no, transaction_no, transaction_type, from_bay_account_no, from_coop_account_no, from_coop_account_name, to_coop_account_no, to_bay_account_no, to_account_name, transaction_amount, transaction_fee, transaction_balance, channel, transaction_date, transaction_time) AS SELECT sc_lon_m_loan_card_detail.seq_no   AS SEQ_NO
         ,sc_lon_m_loan_card_detail.ref_loan_doc_no     AS TRANSACTION_NO
         ,sc_lon_m_loan_card_detail.item_type_code      AS  TRANSACTION_TYPE
         ,'' AS FROM_BAY_ACCOUNT_NO
         ,trim(both sc_lon_m_loan_card.loan_contract_no )    AS FROM_COOP_ACCOUNT_NO
         ,sc_lon_m_rule.loan_type_description           AS  FROM_COOP_ACCOUNT_NAME
         ,'' AS TO_COOP_ACCOUNT_NO
         ,'' AS TO_BAY_ACCOUNT_NO
         ,'' AS TO_ACCOUNT_NAME
         ,sc_lon_m_loan_card_detail.payment_amount   AS TRANSACTION_AMOUNT
         ,sc_lon_m_loan_card_detail.interest_amout      AS TRANSACTION_FEE
         ,sc_lon_m_loan_card_detail.principal_balance      AS TRANSACTION_BALANCE
         ,sc_com_m_branch.branch_name                   AS CHANNEL
         ,to_char( sc_lon_m_loan_card_detail.loan_payment_date,'yyyy-mm-dd')   AS TRANSACTION_DATE
         ,to_char(sc_lon_m_loan_card_detail.entry_date,'dd/mm/yyyy HH24:MI:SS')     AS TRANSACTION_TIME
    FROM sc_lon_m_loan_card_detail
         ,sc_lon_m_loan_card   
         ,sc_lon_m_rule 
         ,sc_com_m_branch
   WHERE sc_lon_m_loan_card_detail.loan_contract_no = sc_lon_m_loan_card.loan_contract_no   
   AND   sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type  
